/// A writer that writes to both stderr (terminal) and shared history sink.
struct DualWriter {
    stderr: io::Stderr,
}

impl Write for DualWriter {
    fn write(&mut self, buf: &[u8]) -> io::Result<usize> {
        // Write to stderr (terminal) - stderr is already thread-safe
        let _ = self.stderr.write_all(buf);
        polymarket_arbitrage_bot::append_history_bytes(buf);

        Ok(buf.len())
    }

    fn flush(&mut self) -> io::Result<()> {
        self.stderr.flush()?;
        polymarket_arbitrage_bot::flush_history_file();
        Ok(())
    }
}

// Make DualWriter Send + Sync for use with env_logger
unsafe impl Send for DualWriter {}
unsafe impl Sync for DualWriter {}

/// Macro to log to both stderr and history.toml (like eprintln! but also saves to file)
#[macro_export]
macro_rules! log_println {
    ($($arg:tt)*) => {
        {
            let message = format!($($arg)*);
            polymarket_arbitrage_bot::log_to_history(&format!("{}\n", message));
        }
    };
}

#[derive(Debug, Clone)]
struct ArbiterExecutionTiming {
    decision_ts_ms: i64,
    enqueue_ts_ms: Option<i64>,
    dequeue_ts_ms: Option<i64>,
    worker_start_ts_ms: Option<i64>,
    submit_start_ts_ms: Option<i64>,
    worker_done_ts_ms: Option<i64>,
    proxy_update_ts_ms: Option<i64>,
    proxy_age_at_decision_ms: Option<i64>,
    proxy_max_age_override_ms: Option<i64>,
}

impl ArbiterExecutionTiming {
    fn new_decision(now_ms: i64) -> Self {
        Self {
            decision_ts_ms: now_ms,
            enqueue_ts_ms: None,
            dequeue_ts_ms: None,
            worker_start_ts_ms: None,
            submit_start_ts_ms: None,
            worker_done_ts_ms: None,
            proxy_update_ts_ms: None,
            proxy_age_at_decision_ms: None,
            proxy_max_age_override_ms: None,
        }
    }

    fn with_proxy_snapshot(
        mut self,
        proxy_update_ts_ms: Option<i64>,
        proxy_age_ms: Option<i64>,
    ) -> Self {
        self.proxy_update_ts_ms = proxy_update_ts_ms.filter(|v| *v > 0);
        self.proxy_age_at_decision_ms = proxy_age_ms.filter(|v| *v >= 0);
        self
    }

    fn with_proxy_max_age_override(mut self, max_age_ms: Option<i64>) -> Self {
        self.proxy_max_age_override_ms =
            max_age_ms.filter(|v| *v >= 50).map(|v| v.clamp(50, 10_000));
        self
    }
}

