fn scale_cap_with_factor(base: usize, factor: f64, min_cap: usize) -> usize {
    if base == 0 {
        return min_cap.max(1);
    }
    let scaled = ((base as f64) * factor.clamp(0.05, 1.0)).floor() as usize;
    scaled.max(min_cap.max(1)).min(base.max(1))
}

