fn maybe_log_premarket_db_throttle_event(
    factor: f64,
    active_cap_base: usize,
    active_cap_scaled: usize,
    submit_cap_base: usize,
    submit_cap_scaled: usize,
) {
    if factor >= 0.999 {
        return;
    }
    let now_ms = chrono::Utc::now().timestamp_millis();
    if let Ok(mut last_ms) = premarket_db_throttle_last_emit_store().lock() {
        if now_ms.saturating_sub(*last_ms) < premarket_db_throttle_event_cooldown_ms() {
            return;
        }
        *last_ms = now_ms;
    }
    let snapshot = db_lock_contention_snapshot();
    log_event(
        "premarket_db_contention_throttle",
        json!({
            "strategy_id": STRATEGY_ID_PREMARKET_V1,
            "factor": factor,
            "active_cap_base": active_cap_base,
            "active_cap_scaled": active_cap_scaled,
            "submit_cap_base": submit_cap_base,
            "submit_cap_scaled": submit_cap_scaled,
            "db_window_ms": snapshot.window_ms,
            "db_samples": snapshot.sample_count,
            "db_wait_p50_ms": snapshot.p50_wait_ms,
            "db_wait_p95_ms": snapshot.p95_wait_ms,
            "db_wait_max_ms": snapshot.max_wait_ms,
            "db_throttle_trigger_p95_ms": snapshot.throttle_trigger_p95_ms
        }),
    );
}

fn maybe_emit_db_contention_alert() {
    let snapshot = db_lock_contention_snapshot();
    if snapshot.sample_count < db_contention_alert_min_samples()
        || snapshot.p95_wait_ms < db_contention_alert_p95_ms()
    {
        return;
    }
    let now_ms = chrono::Utc::now().timestamp_millis();
    if let Ok(mut last_ms) = db_contention_alert_last_emit_store().lock() {
        if now_ms.saturating_sub(*last_ms) < db_contention_alert_cooldown_ms() {
            return;
        }
        *last_ms = now_ms;
    }
    warn!(
        "db contention alert: p95_wait_ms={} samples={} window_ms={} max_wait_ms={} premarket_factor={:.3}",
        snapshot.p95_wait_ms,
        snapshot.sample_count,
        snapshot.window_ms,
        snapshot.max_wait_ms,
        snapshot.recommended_premarket_factor
    );
    log_event(
        "db_contention_alert",
        json!({
            "window_ms": snapshot.window_ms,
            "sample_count": snapshot.sample_count,
            "p50_wait_ms": snapshot.p50_wait_ms,
            "p95_wait_ms": snapshot.p95_wait_ms,
            "max_wait_ms": snapshot.max_wait_ms,
            "alert_p95_ms": db_contention_alert_p95_ms(),
            "recommended_premarket_factor": snapshot.recommended_premarket_factor
        }),
    );
}

fn maybe_emit_late_guard_drop_alert(request: &ArbiterExecutionRequest) {
    let now_ms = chrono::Utc::now().timestamp_millis();
    let window_ms = late_guard_alert_window_ms();
    let threshold = late_guard_alert_threshold();
    let mut count_in_window = 0usize;
    if let Ok(mut guard) = late_guard_drop_timestamps_store().lock() {
        guard.push_back(now_ms);
        while let Some(ts_ms) = guard.front().copied() {
            if now_ms.saturating_sub(ts_ms) <= window_ms {
                break;
            }
            guard.pop_front();
        }
        count_in_window = guard.len();
    }
    if count_in_window < threshold {
        return;
    }
    if let Ok(mut last_ms) = late_guard_alert_last_emit_store().lock() {
        if now_ms.saturating_sub(*last_ms) < late_guard_alert_cooldown_ms() {
            return;
        }
        *last_ms = now_ms;
    }
    warn!(
        "late_guard_drop alert: count={} window_ms={} strategy={} timeframe={}",
        count_in_window,
        window_ms,
        request.intent.strategy_id,
        request_timeframe_label(request)
    );
    log_event(
        "late_guard_drop_alert",
        json!({
            "strategy_id": request.intent.strategy_id,
            "timeframe": request_timeframe_label(request),
            "window_ms": window_ms,
            "count_in_window": count_in_window,
            "threshold": threshold,
            "request_id": request.request_id,
            "token_id": request.opportunity.token_id
        }),
    );
}

fn log_arbiter_request_timing(
    request: &ArbiterExecutionRequest,
    pool_label: &str,
    worker_index: usize,
    status: &str,
    error: Option<&str>,
) {
    if status == "late_guard_drop" {
        maybe_emit_late_guard_drop_alert(request);
    }
    let logical_key = logical_entry_key_from_request(request);
    let symbol = token_family_for_token_type(&request.opportunity.token_type);
    let timing = &request.timing;
    let decision_ts_ms = Some(timing.decision_ts_ms).filter(|v| *v > 0);
    let enqueue_ts_ms = timing.enqueue_ts_ms;
    let dequeue_ts_ms = timing.dequeue_ts_ms;
    let worker_start_ts_ms = timing.worker_start_ts_ms;
    let submit_start_ts_ms = timing.submit_start_ts_ms;
    let worker_done_ts_ms = timing.worker_done_ts_ms;
    let proxy_update_ts_ms = timing.proxy_update_ts_ms;
    let proxy_age_at_decision_ms = timing.proxy_age_at_decision_ms;
    let proxy_max_age_override_ms = timing.proxy_max_age_override_ms;
    log_event(
        "entry_execution_timing",
        json!({
            "request_id": request.request_id,
            "strategy_id": request.intent.strategy_id,
            "timeframe": request_timeframe_label(request),
            "entry_mode": request.entry_mode.as_str(),
            "period_timestamp": request.opportunity.period_timestamp,
            "token_id": request.opportunity.token_id,
            "asset_symbol": symbol,
            "trade_key": logical_key.as_compact_string(),
            "pool": pool_label,
            "worker_index": worker_index,
            "status": status,
            "error": error.unwrap_or(""),
            "decision_ts_ms": decision_ts_ms,
            "enqueue_ts_ms": enqueue_ts_ms,
            "dequeue_ts_ms": dequeue_ts_ms,
            "worker_start_ts_ms": worker_start_ts_ms,
            "submit_start_ts_ms": submit_start_ts_ms,
            "worker_done_ts_ms": worker_done_ts_ms,
            "proxy_update_ts_ms": proxy_update_ts_ms,
            "proxy_age_at_decision_ms": proxy_age_at_decision_ms,
            "proxy_age_at_submit_ms": safe_ms_delta(proxy_update_ts_ms, submit_start_ts_ms),
            "proxy_max_age_override_ms": proxy_max_age_override_ms,
            "decision_to_enqueue_ms": safe_ms_delta(decision_ts_ms, enqueue_ts_ms),
            "queue_wait_ms": safe_ms_delta(enqueue_ts_ms, dequeue_ts_ms),
            "dequeue_to_worker_start_ms": safe_ms_delta(dequeue_ts_ms, worker_start_ts_ms),
            "decision_to_submit_ms": safe_ms_delta(decision_ts_ms, submit_start_ts_ms),
            "submit_runtime_ms": safe_ms_delta(submit_start_ts_ms, worker_done_ts_ms),
            "decision_to_worker_done_ms": safe_ms_delta(decision_ts_ms, worker_done_ts_ms)
        }),
    );
}

#[cfg(test)]
mod execution_timing_tests {
    use super::{safe_ms_delta, timeframe_duration_seconds_from_label};

    #[test]
    fn safe_ms_delta_returns_positive_diff() {
        assert_eq!(safe_ms_delta(Some(100), Some(125)), Some(25));
    }

    #[test]
    fn safe_ms_delta_handles_invalid_ranges() {
        assert_eq!(safe_ms_delta(Some(200), Some(199)), None);
        assert_eq!(safe_ms_delta(None, Some(199)), None);
        assert_eq!(safe_ms_delta(Some(200), None), None);
    }

    #[test]
    fn timeframe_duration_parse_supported_labels() {
        assert_eq!(timeframe_duration_seconds_from_label("5m"), Some(300));
        assert_eq!(timeframe_duration_seconds_from_label("15m"), Some(900));
        assert_eq!(timeframe_duration_seconds_from_label("1h"), Some(3600));
        assert_eq!(timeframe_duration_seconds_from_label("4h"), Some(14400));
        assert_eq!(timeframe_duration_seconds_from_label("1d"), Some(86400));
        assert_eq!(timeframe_duration_seconds_from_label("unknown"), None);
    }
}

async fn enqueue_arbiter_request(
    tx: &tokio::sync::mpsc::Sender<ArbiterExecutionRequest>,
    dedupe_shards: &Arc<Vec<tokio::sync::Mutex<EnqueueDedupe>>>,
    mut request: ArbiterExecutionRequest,
    source: &'static str,
) -> Result<ArbiterEnqueueResult> {
    let now_ms = chrono::Utc::now().timestamp_millis();
    let logical_key = logical_entry_key_from_request(&request);
    let rung_id = request_rung_id(&request);
    let shard_idx = enqueue_dedupe_shard_index(&logical_key, dedupe_shards.len());
    let decision = {
        let dedupe_wait_started = Instant::now();
        let mut guard = dedupe_shards[shard_idx].lock().await;
        let dedupe_wait_ms = i64::try_from(dedupe_wait_started.elapsed().as_millis())
            .ok()
            .unwrap_or(i64::MAX);
        log_runtime_contention(
            "enqueue_dedupe_lock",
            dedupe_wait_ms,
            json!({
                "source": source,
                "shard_idx": shard_idx,
                "request_id": request.request_id,
                "strategy_id": request.intent.strategy_id,
                "timeframe": request_timeframe_label(&request),
                "entry_mode": request.entry_mode.as_str(),
                "rung_id": rung_id
            }),
        );
        guard.should_forward(&logical_key, now_ms)
    };
    if !decision.forwarded {
        log_event(
            "entry_enqueue_deduped",
            json!({
                "source": source,
                "request_id": request.request_id,
                "logical_key": logical_key.as_compact_string(),
                "strategy_id": request.intent.strategy_id,
                "timeframe": request_timeframe_label(&request),
                "entry_mode": request.entry_mode.as_str(),
                "rung_id": rung_id,
                "period_timestamp": request.opportunity.period_timestamp,
                "token_id": request.opportunity.token_id,
                "side": "BUY",
                "reason": format!("{:?}", decision.reason),
                "retry_at_ms": decision.retry_at_ms
            }),
        );
        return Ok(ArbiterEnqueueResult::Deduped);
    }

    if request.timing.enqueue_ts_ms.is_none() {
        request.timing.enqueue_ts_ms = Some(now_ms);
    }
    let send_wait_started = Instant::now();
    tx.send(request)
        .await
        .map_err(|e| anyhow::anyhow!("arbiter channel send failed: {}", e))?;
    let send_wait_ms = i64::try_from(send_wait_started.elapsed().as_millis())
        .ok()
        .unwrap_or(i64::MAX);
    log_runtime_contention(
        "arbiter_channel_send",
        send_wait_ms,
        json!({
            "source": source,
            "strategy_id": logical_key.strategy_id,
            "timeframe": logical_key.timeframe.as_str(),
            "period_timestamp": logical_key.period_timestamp,
            "token_id": logical_key.token_id,
            "rung_id": logical_key.rung_id
        }),
    );
    Ok(ArbiterEnqueueResult::Sent)
}

async fn enqueue_arbiter_request_mm(
    tx: &tokio::sync::mpsc::Sender<ArbiterExecutionRequest>,
    dedupe_shards: &Arc<Vec<tokio::sync::Mutex<EnqueueDedupe>>>,
    mut request: ArbiterExecutionRequest,
    source: &'static str,
    enqueue_mode: mm::MmEnqueueMode,
    enqueue_timeout_ms: u64,
    queue_pressure_telemetry: bool,
) -> Result<MmEnqueueResult> {
    let now_ms = chrono::Utc::now().timestamp_millis();
    let logical_key = logical_entry_key_from_request(&request);
    let rung_id = request_rung_id(&request);
    let shard_idx = enqueue_dedupe_shard_index(&logical_key, dedupe_shards.len());
    let decision = {
        let dedupe_wait_started = Instant::now();
        let mut guard = dedupe_shards[shard_idx].lock().await;
        let dedupe_wait_ms = i64::try_from(dedupe_wait_started.elapsed().as_millis())
            .ok()
            .unwrap_or(i64::MAX);
        log_runtime_contention(
            "enqueue_dedupe_lock",
            dedupe_wait_ms,
            json!({
                "source": source,
                "shard_idx": shard_idx,
                "request_id": request.request_id,
                "strategy_id": request.intent.strategy_id,
                "timeframe": request_timeframe_label(&request),
                "entry_mode": request.entry_mode.as_str(),
                "rung_id": rung_id
            }),
        );
        guard.should_forward(&logical_key, now_ms)
    };
    if !decision.forwarded {
        log_event(
            "entry_enqueue_deduped",
            json!({
                "source": source,
                "request_id": request.request_id,
                "logical_key": logical_key.as_compact_string(),
                "strategy_id": request.intent.strategy_id,
                "timeframe": request_timeframe_label(&request),
                "entry_mode": request.entry_mode.as_str(),
                "rung_id": rung_id,
                "period_timestamp": request.opportunity.period_timestamp,
                "token_id": request.opportunity.token_id,
                "side": "BUY",
                "reason": format!("{:?}", decision.reason),
                "retry_at_ms": decision.retry_at_ms
            }),
        );
        return Ok(MmEnqueueResult::Deduped);
    }

    if request.timing.enqueue_ts_ms.is_none() {
        request.timing.enqueue_ts_ms = Some(now_ms);
    }
    let request_id = request.request_id.clone();
    let strategy_id = request.intent.strategy_id.clone();
    let timeframe = request_timeframe_label(&request);
    let entry_mode = request.entry_mode.as_str().to_string();
    let period_timestamp = request.opportunity.period_timestamp;
    let token_id = request.opportunity.token_id.clone();
    let logical_key_str = logical_key.as_compact_string();
    let tx_available = tx.capacity();
    let tx_max = tx.max_capacity();

    let send_wait_started = Instant::now();
    let sent = match enqueue_mode {
        mm::MmEnqueueMode::Await => {
            tx.send(request)
                .await
                .map_err(|e| anyhow::anyhow!("arbiter channel send failed: {}", e))?;
            true
        }
        mm::MmEnqueueMode::Bounded => {
            let timeout_ms = enqueue_timeout_ms.max(1);
            match tokio::time::timeout(
                tokio::time::Duration::from_millis(timeout_ms),
                tx.send(request),
            )
            .await
            {
                Ok(Ok(())) => true,
                Ok(Err(e)) => {
                    return Err(anyhow::anyhow!("arbiter channel send failed: {}", e));
                }
                Err(_) => false,
            }
        }
        mm::MmEnqueueMode::TrySend => match tx.try_send(request) {
            Ok(()) => true,
            Err(tokio::sync::mpsc::error::TrySendError::Closed(_)) => {
                return Err(anyhow::anyhow!("arbiter channel send failed: closed"));
            }
            Err(tokio::sync::mpsc::error::TrySendError::Full(_)) => false,
        },
    };

    if !sent {
        if queue_pressure_telemetry {
            log_event(
                "entry_enqueue_backpressure_skip",
                json!({
                    "source": source,
                    "request_id": request_id,
                    "logical_key": logical_key_str,
                    "strategy_id": strategy_id,
                    "timeframe": timeframe,
                    "entry_mode": entry_mode,
                    "rung_id": rung_id,
                    "period_timestamp": period_timestamp,
                    "token_id": token_id,
                    "enqueue_mode": enqueue_mode.as_str(),
                    "enqueue_timeout_ms": enqueue_timeout_ms,
                    "tx_available": tx_available,
                    "tx_max": tx_max
                }),
            );
        }
        return Ok(MmEnqueueResult::SkippedBackpressure);
    }

    let send_wait_ms = i64::try_from(send_wait_started.elapsed().as_millis())
        .ok()
        .unwrap_or(i64::MAX);
    log_runtime_contention(
        "arbiter_channel_send",
        send_wait_ms,
        json!({
            "source": source,
            "strategy_id": logical_key.strategy_id,
            "timeframe": logical_key.timeframe.as_str(),
            "period_timestamp": logical_key.period_timestamp,
            "token_id": logical_key.token_id,
            "rung_id": logical_key.rung_id,
            "enqueue_mode": enqueue_mode.as_str()
        }),
    );
    Ok(MmEnqueueResult::Sent)
}

async fn enqueue_arbiter_requests_batch(
    tx: &tokio::sync::mpsc::Sender<ArbiterExecutionRequest>,
    dedupe_shards: &Arc<Vec<tokio::sync::Mutex<EnqueueDedupe>>>,
    requests: Vec<ArbiterExecutionRequest>,
    source: &'static str,
    continue_on_error: bool,
    enqueue_mode: PremarketEnqueueMode,
    enqueue_timeout_ms: u64,
) -> Result<ArbiterBatchEnqueueStats> {
    let mut stats = ArbiterBatchEnqueueStats::default();
    if requests.is_empty() {
        return Ok(stats);
    }

    let shard_count = dedupe_shards.len().max(1);
    let mut buckets: Vec<Vec<(ArbiterExecutionRequest, EntryLogicalKey, Option<String>)>> =
        (0..shard_count).map(|_| Vec::new()).collect();
    for request in requests {
        let logical_key = logical_entry_key_from_request(&request);
        let rung_id = request_rung_id(&request);
        let shard_idx = enqueue_dedupe_shard_index(&logical_key, shard_count);
        if let Some(bucket) = buckets.get_mut(shard_idx) {
            bucket.push((request, logical_key, rung_id));
        }
    }

    let mut send_queue: Vec<(ArbiterExecutionRequest, EntryLogicalKey)> = Vec::new();
    for (shard_idx, bucket) in buckets.iter_mut().enumerate() {
        if bucket.is_empty() {
            continue;
        }
        let dedupe_wait_started = Instant::now();
        let mut guard = dedupe_shards[shard_idx].lock().await;
        let dedupe_wait_ms = i64::try_from(dedupe_wait_started.elapsed().as_millis())
            .ok()
            .unwrap_or(i64::MAX);
        log_runtime_contention(
            "enqueue_dedupe_lock_batch",
            dedupe_wait_ms,
            json!({
                "source": source,
                "shard_idx": shard_idx,
                "request_count": bucket.len()
            }),
        );

        for (request, logical_key, rung_id) in bucket.drain(..) {
            let now_ms = chrono::Utc::now().timestamp_millis();
            let decision = guard.should_forward(&logical_key, now_ms);
            if !decision.forwarded {
                stats.deduped = stats.deduped.saturating_add(1);
                log_event(
                    "entry_enqueue_deduped",
                    json!({
                        "source": source,
                        "request_id": request.request_id,
                        "logical_key": logical_key.as_compact_string(),
                        "strategy_id": request.intent.strategy_id,
                        "timeframe": request_timeframe_label(&request),
                        "entry_mode": request.entry_mode.as_str(),
                        "rung_id": rung_id,
                        "period_timestamp": request.opportunity.period_timestamp,
                        "token_id": request.opportunity.token_id,
                        "side": "BUY",
                        "reason": format!("{:?}", decision.reason),
                        "retry_at_ms": decision.retry_at_ms
                    }),
                );
                continue;
            }
            send_queue.push((request, logical_key));
        }
    }

    for (mut request, logical_key) in send_queue {
        if request.timing.enqueue_ts_ms.is_none() {
            request.timing.enqueue_ts_ms = Some(chrono::Utc::now().timestamp_millis());
        }
        let send_wait_started = Instant::now();
        let send_result: Result<bool, String> = match enqueue_mode {
            PremarketEnqueueMode::Await => tx
                .send(request)
                .await
                .map(|_| true)
                .map_err(|e| format!("arbiter channel send failed: {}", e)),
            PremarketEnqueueMode::Bounded => {
                let timeout_ms = enqueue_timeout_ms.max(1);
                match tokio::time::timeout(
                    tokio::time::Duration::from_millis(timeout_ms),
                    tx.send(request),
                )
                .await
                {
                    Ok(Ok(())) => Ok(true),
                    Ok(Err(e)) => Err(format!("arbiter channel send failed: {}", e)),
                    Err(_) => Ok(false),
                }
            }
            PremarketEnqueueMode::TrySend => match tx.try_send(request) {
                Ok(()) => Ok(true),
                Err(tokio::sync::mpsc::error::TrySendError::Closed(_)) => {
                    Err("arbiter channel send failed: closed".to_string())
                }
                Err(tokio::sync::mpsc::error::TrySendError::Full(_)) => Ok(false),
            },
        };
        let sent = match send_result {
            Ok(v) => v,
            Err(err_text) => {
                stats.failed = stats.failed.saturating_add(1);
                if continue_on_error {
                    log_event(
                        "entry_enqueue_batch_send_error",
                        json!({
                            "source": source,
                            "strategy_id": logical_key.strategy_id,
                            "timeframe": logical_key.timeframe.as_str(),
                            "period_timestamp": logical_key.period_timestamp,
                            "token_id": logical_key.token_id,
                            "rung_id": logical_key.rung_id,
                            "error": err_text,
                            "enqueue_mode": enqueue_mode.as_str(),
                            "enqueue_timeout_ms": enqueue_timeout_ms
                        }),
                    );
                    continue;
                }
                return Err(anyhow::anyhow!(err_text));
            }
        };
        if !sent {
            stats.failed = stats.failed.saturating_add(1);
            if continue_on_error {
                log_event(
                    "entry_enqueue_backpressure_skip",
                    json!({
                        "source": source,
                        "strategy_id": logical_key.strategy_id,
                        "timeframe": logical_key.timeframe.as_str(),
                        "period_timestamp": logical_key.period_timestamp,
                        "token_id": logical_key.token_id,
                        "rung_id": logical_key.rung_id,
                        "enqueue_mode": enqueue_mode.as_str(),
                        "enqueue_timeout_ms": enqueue_timeout_ms
                    }),
                );
                continue;
            }
            return Err(anyhow::anyhow!(
                "arbiter channel send skipped by backpressure source={} strategy={} tf={} token={}",
                source,
                logical_key.strategy_id,
                logical_key.timeframe.as_str(),
                logical_key.token_id
            ));
        }
        let send_wait_ms = i64::try_from(send_wait_started.elapsed().as_millis())
            .ok()
            .unwrap_or(i64::MAX);
        log_runtime_contention(
            "arbiter_channel_send_batch",
            send_wait_ms,
            json!({
                "source": source,
                "strategy_id": logical_key.strategy_id,
                "timeframe": logical_key.timeframe.as_str(),
                "period_timestamp": logical_key.period_timestamp,
                "token_id": logical_key.token_id,
                "rung_id": logical_key.rung_id,
                "enqueue_mode": enqueue_mode.as_str()
            }),
        );
        stats.sent = stats.sent.saturating_add(1);
    }

    Ok(stats)
}

fn round_price_to_tick(price: f64, tick: f64) -> f64 {
    if tick <= 0.0 {
        return price;
    }
    (price / tick).round() * tick
}

fn endgame_sweep_poly_price_band_for_tick(tick_index: u32) -> (f64, f64) {
    if let Ok(raw) = std::env::var("EVPOLY_ENDGAME_SWEEP_POLY_PRICE_BAND") {
        if let Some(parsed) = parse_price_band(raw.as_str()) {
            return parsed;
        }
    }
    let tick_key = format!("EVPOLY_ENDGAME_SWEEP_POLY_PRICE_BAND_TICK{}", tick_index);
    if let Ok(raw) = std::env::var(tick_key.as_str()) {
        if let Some(parsed) = parse_price_band(raw.as_str()) {
            return parsed;
        }
    }
    match tick_index {
        0 => (0.95, 0.99),
        1 => (0.97, 0.99),
        _ => (0.98, 0.99),
    }
}

fn parse_price_band(raw: &str) -> Option<(f64, f64)> {
    let (min_raw, max_raw) = raw.split_once('-')?;
    let min_v = min_raw.trim().parse::<f64>().ok()?;
    let max_v = max_raw.trim().parse::<f64>().ok()?;
    if !min_v.is_finite() || !max_v.is_finite() || min_v <= 0.0 || max_v < min_v {
        return None;
    }
    Some((min_v.clamp(0.01, 0.99), max_v.clamp(0.01, 0.99)))
}

fn to_json_string(value: Value) -> Option<String> {
    serde_json::to_string(&value).ok()
}

fn upsert_feature_snapshot(
    db: &TrackingDb,
    row: StrategyFeatureSnapshotIntentRecord,
    context: &str,
) {
    if let Err(e) = db.upsert_strategy_feature_snapshot_intent(&row) {
        warn!("{} snapshot upsert failed: {}", context, e);
    }
}

fn premarket_batch_continue_on_error() -> bool {
    std::env::var("EVPOLY_PREMARKET_BATCH_CONTINUE_ON_ERROR")
        .ok()
        .map(|v| {
            matches!(
                v.trim().to_ascii_lowercase().as_str(),
                "1" | "true" | "yes" | "on"
            )
        })
        .unwrap_or(false)
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum PremarketEnqueueMode {
    Await,
    Bounded,
    TrySend,
}

impl PremarketEnqueueMode {
    fn from_env() -> Self {
        match std::env::var("EVPOLY_PREMARKET_ENQUEUE_MODE")
            .ok()
            .unwrap_or_else(|| "bounded".to_string())
            .trim()
            .to_ascii_lowercase()
            .as_str()
        {
            "await" => Self::Await,
            "try_send" | "trysend" | "try" => Self::TrySend,
            _ => Self::Bounded,
        }
    }

    fn as_str(self) -> &'static str {
        match self {
            Self::Await => "await",
            Self::Bounded => "bounded",
            Self::TrySend => "try_send",
        }
    }
}

fn premarket_enqueue_timeout_ms() -> u64 {
    std::env::var("EVPOLY_PREMARKET_ENQUEUE_TIMEOUT_MS")
        .ok()
        .and_then(|v| v.trim().parse::<u64>().ok())
        .unwrap_or(120)
        .clamp(10, 5_000)
}

fn premarket_enqueue_guard_ms() -> i64 {
    std::env::var("EVPOLY_PREMARKET_ENQUEUE_GUARD_MS")
        .ok()
        .and_then(|v| v.trim().parse::<i64>().ok())
        .unwrap_or(15_000)
        .max(0)
}

fn premarket_batch_chunk_for_seconds_to_open(base_chunk: usize, seconds_to_open: i64) -> usize {
    if seconds_to_open <= 20 {
        base_chunk.min(4).max(1)
    } else if seconds_to_open <= 45 {
        base_chunk.min(8).max(1)
    } else {
        base_chunk.max(1)
    }
}

fn premarket_enqueue_mode_for_seconds_to_open(
    default_mode: PremarketEnqueueMode,
    seconds_to_open: i64,
) -> PremarketEnqueueMode {
    if seconds_to_open <= 20 {
        PremarketEnqueueMode::TrySend
    } else {
        default_mode
    }
}

fn premarket_enqueue_timeout_for_seconds_to_open(
    default_timeout_ms: u64,
    seconds_to_open: i64,
) -> u64 {
    if seconds_to_open <= 20 {
        default_timeout_ms.min(40).max(5)
    } else if seconds_to_open <= 45 {
        default_timeout_ms.min(80).max(10)
    } else {
        default_timeout_ms
    }
}

#[derive(Debug, Clone, Copy)]
struct PremarketOrderFloor {
    min_notional_usd: f64,
    min_size_shares: f64,
}

impl PremarketOrderFloor {
    fn from_snapshot(snapshot: polymarket_arbitrage_bot::api::MarketConstraintSnapshot) -> Self {
        let min_notional_usd = f64::try_from(snapshot.minimum_order_size)
            .unwrap_or(5.0)
            .max(0.0);
        let min_size_shares = f64::try_from(snapshot.min_size_shares)
            .unwrap_or(0.0)
            .max(0.0);
        Self {
            min_notional_usd,
            min_size_shares,
        }
    }

    fn fallback_default() -> Self {
        Self {
            min_notional_usd: 5.0,
            min_size_shares: 0.0,
        }
    }

    fn required_notional_usd(self, price: f64) -> f64 {
        let safe_price = price.max(0.000001);
        let share_floor = if self.min_size_shares > 0.0 {
            self.min_size_shares * safe_price
        } else {
            0.0
        };
        self.min_notional_usd.max(share_floor).max(0.0)
    }

    // Polymarket "rewards.min_size" is an incentive target, not a hard CLOB minimum.
    // Exit logic should honor exchange floor only, otherwise dead-capital exits can stall.
    fn exchange_min_shares(self, price: f64) -> f64 {
        let safe_price = price.max(0.000001);
        (self.min_notional_usd.max(0.0) / safe_price).max(1.0)
    }
}

fn mm_reward_min_shares_for_price(
    reward_min_size: f64,
    submit_price: f64,
    unit: mm::MmRewardMinSizeUnit,
) -> f64 {
    let min_size = reward_min_size.max(0.0);
    if min_size <= 0.0 {
        return 0.0;
    }
    let safe_price = submit_price.max(0.000001);
    match unit {
        mm::MmRewardMinSizeUnit::Shares => min_size,
        mm::MmRewardMinSizeUnit::Usd => min_size / safe_price,
    }
}

fn mm_reward_min_shares_with_policy(
    reward_min_size: f64,
    submit_price: f64,
    reference_price: Option<f64>,
    unit: mm::MmRewardMinSizeUnit,
    target_mult: f64,
    floor_mode: mm::MmRewardMinFloorMode,
    floor_max_mult: f64,
    shares_cap: f64,
) -> f64 {
    let per_rung = mm_reward_min_shares_for_price(reward_min_size, submit_price, unit).max(0.0);
    let reference_submit_price = reference_price
        .filter(|v| v.is_finite() && *v > 0.0)
        .unwrap_or(submit_price);
    let reference =
        mm_reward_min_shares_for_price(reward_min_size, reference_submit_price, unit).max(0.0);
    let mode_adjusted = match floor_mode {
        mm::MmRewardMinFloorMode::PerRung => per_rung,
        mm::MmRewardMinFloorMode::ReferencePrice => reference,
        mm::MmRewardMinFloorMode::Hybrid => {
            let max_mult = floor_max_mult.max(1.0);
            let max_allowed = (reference * max_mult).max(reference);
            per_rung.min(max_allowed)
        }
    };
    let target_mult = if target_mult.is_finite() {
        target_mult.max(0.0)
    } else {
        1.0
    };
    let target_scaled = (mode_adjusted.max(0.0) * target_mult).max(0.0);
    if shares_cap.is_finite() && shares_cap > 0.0 {
        target_scaled.min(shares_cap).max(0.0)
    } else {
        target_scaled.max(0.0)
    }
}

#[derive(Debug, Clone)]
struct PremarketSizedRung {
    price: f64,
    size_usd: f64,
    size_pct: f64,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
struct PremarketAssetSpec {
    market_key: &'static str,
    asset_symbol: &'static str,
    symbol_family: &'static str,
}

impl PremarketAssetSpec {
    fn token_type_for_direction(self, direction: Direction) -> crate::detector::TokenType {
        token_type_for_asset_direction(self.asset_symbol, direction)
    }
}

const PREMARKET_ASSET_BTC: PremarketAssetSpec = PremarketAssetSpec {
    market_key: "btc",
    asset_symbol: "BTC",
    symbol_family: "BTC",
};

const PREMARKET_ASSET_ETH: PremarketAssetSpec = PremarketAssetSpec {
    market_key: "eth",
    asset_symbol: "ETH",
    symbol_family: "ETH",
};

const PREMARKET_ASSET_SOL: PremarketAssetSpec = PremarketAssetSpec {
    market_key: "sol",
    asset_symbol: "SOL",
    symbol_family: "SOL",
};

const PREMARKET_ASSET_XRP: PremarketAssetSpec = PremarketAssetSpec {
    market_key: "xrp",
    asset_symbol: "XRP",
    symbol_family: "XRP",
};

fn premarket_enabled_assets(
    enable_eth_trading: bool,
    enable_solana_trading: bool,
    enable_xrp_trading: bool,
) -> Vec<PremarketAssetSpec> {
    let mut assets = vec![PREMARKET_ASSET_BTC];
    if enable_eth_trading {
        assets.push(PREMARKET_ASSET_ETH);
    }
    if enable_solana_trading {
        assets.push(PREMARKET_ASSET_SOL);
    }
    if enable_xrp_trading {
        assets.push(PREMARKET_ASSET_XRP);
    }
    assets
}

#[derive(Debug, Clone, Copy)]
struct PremarketCancelStage {
    label: &'static str,
    offset_seconds: i64,
    cancel_price_above: Option<f64>,
}

fn premarket_cancel_stages_for_timeframe(timeframe: Timeframe) -> Vec<PremarketCancelStage> {
    let pre_trim_20 = std::env::var("EVPOLY_PREMARKET_CANCEL_PREOPEN_TRIM_20_OFFSET_SEC")
        .ok()
        .and_then(|v| v.trim().parse::<i64>().ok())
        .unwrap_or(-15)
        .clamp(-300, 0);
    let pre_trim_15 = std::env::var("EVPOLY_PREMARKET_CANCEL_PREOPEN_TRIM_15_OFFSET_SEC")
        .ok()
        .and_then(|v| v.trim().parse::<i64>().ok())
        .unwrap_or(-5)
        .clamp(-300, 0);
    let post_open = premarket_post_open_cancel_offset_seconds(timeframe);
    vec![
        PremarketCancelStage {
            label: "pre_open_trim_20",
            offset_seconds: pre_trim_20,
            cancel_price_above: Some(0.20),
        },
        PremarketCancelStage {
            label: "pre_open_trim_15",
            offset_seconds: pre_trim_15,
            cancel_price_above: Some(0.15),
        },
        PremarketCancelStage {
            label: "post_open_cancel_all",
            offset_seconds: post_open,
            cancel_price_above: None,
        },
    ]
}

fn premarket_post_open_cancel_offset_seconds(timeframe: Timeframe) -> i64 {
    let (key, default) = match timeframe {
        Timeframe::M5 => ("EVPOLY_PREMARKET_CANCEL_AFTER_OPEN_5M_SEC", 20_i64),
        Timeframe::M15 => ("EVPOLY_PREMARKET_CANCEL_AFTER_OPEN_15M_SEC", 40_i64),
        Timeframe::H1 => ("EVPOLY_PREMARKET_CANCEL_AFTER_OPEN_1H_SEC", 60_i64),
        Timeframe::H4 => ("EVPOLY_PREMARKET_CANCEL_AFTER_OPEN_4H_SEC", 180_i64),
        Timeframe::D1 => ("EVPOLY_PREMARKET_CANCEL_AFTER_OPEN_4H_SEC", 180_i64),
    };
    std::env::var(key)
        .ok()
        .and_then(|v| v.trim().parse::<i64>().ok())
        .unwrap_or(default)
        .clamp(0, 900)
}

fn premarket_side_budget_usd(timeframe: Timeframe) -> f64 {
    let base_size_usd = size_policy::base_size_usd_from_env("EVPOLY_PREMARKET_BASE_SIZE_USD");
    let timeframe_multiplier = size_policy::premarket_timeframe_multiplier(timeframe);
    (base_size_usd * timeframe_multiplier).max(0.0)
}

fn premarket_side_budget_multiplier(asset_symbol: &str) -> f64 {
    size_policy::symbol_size_multiplier(asset_symbol)
}

fn premarket_side_budget_usd_for_asset(timeframe: Timeframe, asset_symbol: &str) -> f64 {
    premarket_side_budget_usd(timeframe) * premarket_side_budget_multiplier(asset_symbol)
}

fn premarket_submit_cap_per_token() -> usize {
    // Hardcoded premarket submit cap to prevent BTC/ETH inflight submit pressure
    // from blocking SOL/XRP requests in the same timeframe window.
    48
}

fn premarket_fixed_ladder_prices() -> &'static [f64] {
    const PRICES: [f64; 6] = [0.40, 0.30, 0.24, 0.21, 0.15, 0.12];
    &PRICES
}

fn premarket_fixed_ladder_weights() -> &'static [f64] {
    const WEIGHTS: [f64; 6] = [0.23, 0.23, 0.17, 0.14, 0.12, 0.11];
    &WEIGHTS
}

fn build_premarket_fixed_rungs(
    target_size_usd: f64,
    floor: PremarketOrderFloor,
) -> Vec<PremarketSizedRung> {
    if target_size_usd <= 0.0 {
        return Vec::new();
    }

    let prices = premarket_fixed_ladder_prices();
    let weights = premarket_fixed_ladder_weights();
    let rung_count = prices.len().min(weights.len());
    let mut rungs = Vec::with_capacity(rung_count);
    for idx in 0..rung_count {
        let price = prices[idx].clamp(0.01, 0.99);
        let size_pct = weights[idx].max(0.0);
        let mut size_usd = target_size_usd * size_pct;
        let min_required = floor.required_notional_usd(price);
        if size_usd + 1e-9 < min_required {
            size_usd = min_required;
        }
        if !size_usd.is_finite() || size_usd <= 0.0 {
            continue;
        }
        rungs.push(PremarketSizedRung {
            price,
            size_usd,
            size_pct,
        });
    }
    rungs
}

fn canonical_strategy_period_key(decision: &StrategyDecision, fallback_period_ts: u64) -> u64 {
    u64::try_from(decision.market_open_ts)
        .ok()
        .filter(|ts| *ts > 0)
        .unwrap_or(fallback_period_ts)
}

fn token_family_for_token_type(token_type: &crate::detector::TokenType) -> &'static str {
    use crate::detector::TokenType;
    match token_type {
        TokenType::BtcUp | TokenType::BtcDown => "BTC",
        TokenType::EthUp | TokenType::EthDown => "ETH",
        TokenType::SolanaUp | TokenType::SolanaDown => "SOL",
        TokenType::XrpUp | TokenType::XrpDown => "XRP",
    }
}

fn token_type_for_asset_direction(
    asset_symbol: &str,
    direction: Direction,
) -> crate::detector::TokenType {
    let normalized = asset_symbol.trim().to_ascii_uppercase();
    match (normalized.as_str(), direction) {
        ("ETH", Direction::Up) => crate::detector::TokenType::EthUp,
        ("ETH", Direction::Down) => crate::detector::TokenType::EthDown,
        ("SOL", Direction::Up) | ("SOLANA", Direction::Up) => crate::detector::TokenType::SolanaUp,
        ("SOL", Direction::Down) | ("SOLANA", Direction::Down) => {
            crate::detector::TokenType::SolanaDown
        }
        ("XRP", Direction::Up) => crate::detector::TokenType::XrpUp,
        ("XRP", Direction::Down) => crate::detector::TokenType::XrpDown,
        (_, Direction::Up) => crate::detector::TokenType::BtcUp,
        (_, Direction::Down) => crate::detector::TokenType::BtcDown,
    }
}

fn normalize_market_symbol(symbol: &str) -> String {
    match symbol.trim().to_ascii_uppercase().as_str() {
        "BTC" => "BTC".to_string(),
        "ETH" => "ETH".to_string(),
        "SOL" | "SOLANA" => "SOL".to_string(),
        "XRP" => "XRP".to_string(),
        other => other.to_string(),
    }
}

fn market_symbol_slug_prefixes(symbol: &str) -> &'static [&'static str] {
    match normalize_market_symbol(symbol).as_str() {
        "BTC" => &["btc"],
        "ETH" => &["eth"],
        "SOL" => &["sol", "solana"],
        "XRP" => &["xrp"],
        _ => &["btc"],
    }
}

fn coinbase_product_id_for_market_symbol(symbol: &str) -> Option<&'static str> {
    match normalize_market_symbol(symbol).as_str() {
        "BTC" => Some("BTC-USD"),
        "ETH" => Some("ETH-USD"),
        "SOL" => Some("SOL-USD"),
        "XRP" => Some("XRP-USD"),
        _ => None,
    }
}

fn market_symbol_from_coinbase_product_id(product_id: &str) -> Option<&'static str> {
    match product_id.trim().to_ascii_uppercase().as_str() {
        "BTC-USD" => Some("BTC"),
        "ETH-USD" => Some("ETH"),
        "SOL-USD" => Some("SOL"),
        "XRP-USD" => Some("XRP"),
        _ => None,
    }
}

fn token_type_for_market_symbol(symbol: &str, direction: Direction) -> crate::detector::TokenType {
    let normalized = normalize_market_symbol(symbol);
    match (normalized.as_str(), direction) {
        ("ETH", Direction::Up) => crate::detector::TokenType::EthUp,
        ("ETH", Direction::Down) => crate::detector::TokenType::EthDown,
        ("SOL", Direction::Up) => crate::detector::TokenType::SolanaUp,
        ("SOL", Direction::Down) => crate::detector::TokenType::SolanaDown,
        ("XRP", Direction::Up) => crate::detector::TokenType::XrpUp,
        ("XRP", Direction::Down) => crate::detector::TokenType::XrpDown,
        (_, Direction::Up) => crate::detector::TokenType::BtcUp,
        (_, Direction::Down) => crate::detector::TokenType::BtcDown,
    }
}

fn d1_period_bounds_for_timestamp(ts: i64) -> Option<(i64, i64)> {
    use chrono::TimeZone;

    let dt_utc = chrono::DateTime::<Utc>::from_timestamp(ts, 0)?;
    let dt_et = dt_utc.with_timezone(&New_York);
    let date = dt_et.date_naive();
    let noon_today = New_York
        .with_ymd_and_hms(date.year(), date.month(), date.day(), 12, 0, 0)
        .single()?;
    let open_et = if dt_et >= noon_today {
        noon_today
    } else {
        noon_today - chrono::Duration::days(1)
    };
    let close_et = open_et + chrono::Duration::days(1);
    Some((
        open_et.with_timezone(&Utc).timestamp(),
        close_et.with_timezone(&Utc).timestamp(),
    ))
}

fn timeframe_slug_candidates(timeframe: Timeframe) -> &'static [&'static str] {
    match timeframe {
        Timeframe::M5 => &["5m"],
        Timeframe::M15 => &["15m"],
        Timeframe::H1 => &["1h", "60m", "hourly"],
        Timeframe::H4 => &["4h", "240m"],
        Timeframe::D1 => &["1d", "24h", "daily"],
    }
}

fn market_prewarm_horizon_periods(timeframe: Timeframe) -> u64 {
    match timeframe {
        Timeframe::M5 => std::env::var("EVPOLY_MARKET_PREWARM_HORIZON_5M")
            .ok()
            .and_then(|v| v.parse::<u64>().ok())
            .unwrap_or(2),
        Timeframe::M15 => std::env::var("EVPOLY_MARKET_PREWARM_HORIZON_15M")
            .ok()
            .and_then(|v| v.parse::<u64>().ok())
            .unwrap_or(2),
        Timeframe::H1 => std::env::var("EVPOLY_MARKET_PREWARM_HORIZON_1H")
            .ok()
            .and_then(|v| v.parse::<u64>().ok())
            .unwrap_or(1),
        Timeframe::H4 => std::env::var("EVPOLY_MARKET_PREWARM_HORIZON_4H")
            .ok()
            .and_then(|v| v.parse::<u64>().ok())
            .unwrap_or(1),
        Timeframe::D1 => std::env::var("EVPOLY_MARKET_PREWARM_HORIZON_1D")
            .ok()
            .and_then(|v| v.parse::<u64>().ok())
            .unwrap_or(1),
    }
}

fn timeframe_open_ts_for_ahead(now_ts: u64, timeframe: Timeframe, periods_ahead: u64) -> u64 {
    if timeframe == Timeframe::D1 {
        if let Some((open_ts, close_ts)) = d1_period_bounds_for_timestamp(now_ts as i64) {
            let period_secs = close_ts.saturating_sub(open_ts).max(1) as u64;
            return (open_ts as u64).saturating_add(period_secs.saturating_mul(periods_ahead));
        }
    }
    let period_secs = timeframe.duration_seconds().max(1) as u64;
    let current_open = (now_ts / period_secs) * period_secs;
    current_open.saturating_add(period_secs.saturating_mul(periods_ahead))
}

