    #[test]
    fn best_bid_ask_sizes_aggregate_top_level_sizes() {
        let orderbook = polymarket_arbitrage_bot::models::OrderBook {
            bids: vec![
                polymarket_arbitrage_bot::models::OrderBookEntry {
                    price: rust_decimal::Decimal::new(50, 2),
                    size: rust_decimal::Decimal::new(100, 0),
                },
                polymarket_arbitrage_bot::models::OrderBookEntry {
                    price: rust_decimal::Decimal::new(50, 2),
                    size: rust_decimal::Decimal::new(40, 0),
                },
                polymarket_arbitrage_bot::models::OrderBookEntry {
                    price: rust_decimal::Decimal::new(49, 2),
                    size: rust_decimal::Decimal::new(80, 0),
                },
            ],
            asks: vec![
                polymarket_arbitrage_bot::models::OrderBookEntry {
                    price: rust_decimal::Decimal::new(51, 2),
                    size: rust_decimal::Decimal::new(30, 0),
                },
                polymarket_arbitrage_bot::models::OrderBookEntry {
                    price: rust_decimal::Decimal::new(51, 2),
                    size: rust_decimal::Decimal::new(20, 0),
                },
                polymarket_arbitrage_bot::models::OrderBookEntry {
                    price: rust_decimal::Decimal::new(52, 2),
                    size: rust_decimal::Decimal::new(10, 0),
                },
            ],
        };
        let (best_bid, best_ask, best_bid_size, best_ask_size) =
            best_bid_ask_sizes_from_orderbook(&orderbook);
        assert_eq!(best_bid, Some(0.50));
        assert_eq!(best_ask, Some(0.51));
        assert_eq!(best_bid_size, Some(140.0));
        assert_eq!(best_ask_size, Some(50.0));
    }

    #[test]
    fn h1_candidates_target_first() {
        let target_open_ts = 1_771_574_400_u64; // 2026-02-20 08:00:00 UTC (3am ET)
        let now_utc = chrono::DateTime::<Utc>::from_timestamp(target_open_ts as i64, 0)
            .expect("valid target timestamp");
        let candidates =
            h1_bitcoin_event_slug_candidates_with_policy(now_utc, target_open_ts, true);

        assert!(!candidates.is_empty());
        assert_eq!(candidates[0].source, "target");
        assert_eq!(candidates[0].open_ts, target_open_ts);
        assert_eq!(
            candidates[0].slug,
            h1_target_slug_for_open_ts(target_open_ts).expect("target slug")
        );
    }

