    #[test]
    fn h1_discovery_rejects_future_when_strict() {
        let target_open_ts = 1_771_574_400_u64;
        let future_open_ts = target_open_ts + 3600;
        assert!(h1_discovery_candidate_allowed_for_target(
            target_open_ts,
            target_open_ts,
            true
        ));
        assert!(!h1_discovery_candidate_allowed_for_target(
            future_open_ts,
            target_open_ts,
            true
        ));
    }

    #[test]
    fn h1_discovery_allows_future_only_when_flag_enabled() {
        let target_open_ts = 1_771_574_400_u64; // 08:00 UTC
        let now_utc = chrono::DateTime::<Utc>::from_timestamp(target_open_ts as i64, 0)
            .expect("valid target timestamp");

        let strict_candidates =
            h1_bitcoin_event_slug_candidates_with_policy(now_utc, target_open_ts, false);
        assert!(strict_candidates
            .iter()
            .all(|candidate| candidate.source != "next_hour_fallback"));

        let fallback_candidates =
            h1_bitcoin_event_slug_candidates_with_policy(now_utc, target_open_ts, true);
        assert!(fallback_candidates
            .iter()
            .any(|candidate| candidate.source == "next_hour_fallback"));
    }

    #[test]
    fn h1_mismatch_blocks_submit_and_emits_event() {
        let target_open_ts = 1_771_574_400_u64;
        let target_slug = h1_target_slug_for_open_ts(target_open_ts).expect("target slug");
        let eth_target_slug =
            h1_target_slug_for_open_ts_for_symbol("ETH", target_open_ts).expect("eth target slug");
        let future_slug =
            h1_target_slug_for_open_ts(target_open_ts + 3600).expect("future target slug");
        let eth_future_slug = h1_target_slug_for_open_ts_for_symbol("ETH", target_open_ts + 3600)
            .expect("eth future target slug");

        assert!(!h1_market_period_mismatch_for_trade(
            Timeframe::H1,
            target_open_ts,
            target_open_ts,
            target_slug.as_str()
        ));
        assert!(!h1_market_period_mismatch_for_trade(
            Timeframe::H1,
            target_open_ts,
            target_open_ts,
            eth_target_slug.as_str()
        ));
        assert!(!h1_market_period_mismatch_for_trade(
            Timeframe::H1,
            target_open_ts,
            target_open_ts,
            format!("eth-updown-1h-{}", target_open_ts).as_str()
        ));
        assert!(h1_market_period_mismatch_for_trade(
            Timeframe::H1,
            target_open_ts,
            target_open_ts,
            future_slug.as_str()
        ));
        assert!(h1_market_period_mismatch_for_trade(
            Timeframe::H1,
            target_open_ts,
            target_open_ts,
            eth_future_slug.as_str()
        ));
        assert!(h1_market_period_mismatch_for_trade(
            Timeframe::H1,
            target_open_ts,
            target_open_ts + 3600,
            target_slug.as_str()
        ));
    }
